from functools import lru_cache

class Solution:
    def totalWaviness(self, num1, num2):
        def cum_waviness_dp(N):
            if N <= 0:
                return 0
            s = str(N)
            L = len(s)
            digits = [int(c) for c in s]
            total = 0

            def free_dp(length):
                @lru_cache(maxsize=None)
                def rec(idx, p2, p1):
                    if idx == length:
                        return (1, 0)
                    cnt_total = 0
                    sum_total = 0
                    lo = 1 if idx == 0 else 0
                    for d in range(lo, 10):
                        contrib = 0
                        if idx >= 2 and ((p2 < p1 > d) or (p2 > p1 < d)):
                            contrib = 1
                        subcnt, subsum = rec(idx + 1, p1, d)
                        cnt_total += subcnt
                        sum_total += subsum + contrib * subcnt
                    return (cnt_total, sum_total)
                _, sm = rec(0, -1, -1)
                rec.cache_clear()
                return sm

            for length in range(1, L):
                total += free_dp(length)

            @lru_cache(maxsize=None)
            def rec_tight(idx, p2, p1, tight):
                if idx == L:
                    return (1, 0)
                cnt_total = 0
                sum_total = 0
                hi = digits[idx] if tight else 9
                lo = 1 if idx == 0 else 0
                for d in range(lo, hi + 1):
                    contrib = 0
                    if idx >= 2 and ((p2 < p1 > d) or (p2 > p1 < d)):
                        contrib = 1
                    ntight = tight and (d == hi)
                    subcnt, subsum = rec_tight(idx + 1, p1, d, ntight)
                    cnt_total += subcnt
                    sum_total += subsum + contrib * subcnt
                return (cnt_total, sum_total)

            _, sm = rec_tight(0, -1, -1, True)
            rec_tight.cache_clear()
            total += sm
            return total
        return cum_waviness_dp(num2) - cum_waviness_dp(num1 - 1)

