class Solution:
    def totalWaviness(self, num1, num2):
        def waviness(x):
            s = str(x)
            L = len(s)
            if L < 3:
                return 0
            c = 0
            for i in range(1, L - 1):
                a, b, cc = int(s[i - 1]), int(s[i]), int(s[i + 1])
                if (a < b > cc) or (a > b < cc):
                    c += 1
            return c
        total = 0
        for x in range(num1, num2 + 1):
            total += waviness(x)
        return total

