var totalWaviness = function(num1, num2) {
    function waviness(x) {
        const s = String(x);
        const L = s.length;
        if (L < 3) return 0;
        let c = 0;
        for (let i = 1; i < L - 1; i++) {
            const a = Number(s[i - 1]), b = Number(s[i]), cc = Number(s[i + 1]);
            if ((a < b && b > cc) || (a > b && b < cc)) c++;
        }
        return c;
    }
    let total = 0;
    for (let x = num1; x <= num2; x++) total += waviness(x);
    return total;
};
